import React, { useState, useEffect, useRef } from 'react';
import './App.css';
import FileUpload from './components/FileUpload';
import EventSelection from './components/EventSelection';
import ManualInput from './components/ManualInput';
import DetectedItems from './components/DetectedItems';
import MaterialChart from './components/MaterialChart';
import LanguageToggle from './components/LanguageToggle';
import VoiceOutput from './components/VoiceOutput';
import VoiceCommands from './components/VoiceCommands';
import PandaLoader from './components/PandaLoader';
import { fetchDetectedItems } from './services/api';

function App() {
  const [language, setLanguage] = useState('en');
  const [uploadedFile, setUploadedFile] = useState(null);
  const [selectedEvent, setSelectedEvent] = useState('');
  const [manualItems, setManualItems] = useState([]);
  const [detectedItems, setDetectedItems] = useState([]);
  const [materialData, setMaterialData] = useState({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showResults, setShowResults] = useState(false);
  const [currentStep, setCurrentStep] = useState(0);
  const fileInputRef = useRef(null);

  const steps = [
    'voice-commands',
    'file-upload', 
    'event-selection',
    'manual-input',
    'analyze',
    'results-chart',
    'results-items'
  ];

  const translations = {
    en: {
      title: 'AI Event Decor Material Analyzer',
      analyze: 'Analyze Materials',
      analyzing: 'Analyzing event materials...',
      allMaterialsPresent: '✅ All materials are present',
      someMaterialsMissing: '❌ Some materials are missing',
      missingItems: 'Missing Items:',
      steps: {
        'voice-commands': { title: 'Voice Commands', subtitle: 'Control the app with your voice' },
        'file-upload': { title: 'Upload Media', subtitle: 'Upload images or videos of your event setup' },
        'event-selection': { title: 'Event Type', subtitle: 'Select the type of event you\'re planning' },
        'manual-input': { title: 'Add Items', subtitle: 'Manually add decoration items' },
        'analyze': { title: 'Analyze', subtitle: 'Process and analyze your materials' },
        'results-chart': { title: 'Material Chart', subtitle: 'View material distribution' },
        'results-items': { title: 'Detected Items', subtitle: 'Review all detected items' }
      },
      navigation: {
        previous: '← Previous',
        next: 'Next →',
        finish: 'Finish'
      }
    },
    ta: {
      title: 'AI நிகழ்வு அலங்கார பொருள் பகுப்பாய்வி',
      analyze: 'பொருட்களை பகுப்பாய்வு செய்யுங்கள்',
      analyzing: 'நிகழ்வு பொருட்களை பகுப்பாய்வு செய்கிறது...',
      allMaterialsPresent: '✅ அனைத்து பொருட்களும் உள்ளன',
      someMaterialsMissing: '❌ சில பொருட்கள் இல்லை',
      missingItems: 'இல்லாத பொருட்கள்:',
      steps: {
        'voice-commands': { title: 'குரல் கட்டளைகள்', subtitle: 'குரல் மூலம் ஆப்ஸை கட்டுப்படுத்துங்கள்' },
        'file-upload': { title: 'மீடியா பதிவேற்றம்', subtitle: 'உங்கள் நிகழ்வு அமைப்பின் படங்கள் அல்லது வீடியோக்களை பதிவேற்றவும்' },
        'event-selection': { title: 'நிகழ்வு வகை', subtitle: 'நீங்கள் திட்டமிடும் நிகழ்வின் வகையை தேர்ந்தெடுக்கவும்' },
        'manual-input': { title: 'பொருட்கள் சேர்க்க', subtitle: 'அலங்கார பொருட்களை கைமுறையாக சேர்க்கவும்' },
        'analyze': { title: 'பகுப்பாய்வு', subtitle: 'உங்கள் பொருட்களை செயலாக்கி பகுப்பாய்வு செய்யுங்கள்' },
        'results-chart': { title: 'பொருள் விளக்கப்படம்', subtitle: 'பொருள் விநியோகத்தை பார்க்கவும்' },
        'results-items': { title: 'கண்டறியப்பட்ட பொருட்கள்', subtitle: 'அனைத்து கண்டறியப்பட்ட பொருட்களையும் மதிப்பாய்வு செய்யுங்கள்' }
      },
      navigation: {
        previous: '← முந்தைய',
        next: 'அடுத்து →',
        finish: 'முடிக்க'
      }
    }
  };

  useEffect(() => {
    updateMaterialData();
  }, [detectedItems, manualItems]);

  const handleAnalyze = async () => {
    if (!uploadedFile && manualItems.length === 0) {
      setError('Please upload a file or add manual items before analyzing.');
      return;
    }

    setLoading(true);
    setError(null);
    setShowResults(false);
    
    try {
      if (uploadedFile) {
        const items = await fetchDetectedItems(uploadedFile);
        setDetectedItems(items);
      }
      setShowResults(true);
    } catch (err) {
      setError('Failed to analyze materials. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const updateMaterialData = () => {
    const allItems = [...detectedItems, ...manualItems];
    const materials = {};
    
    allItems.forEach(item => {
      if (item.material) {
        materials[item.material] = (materials[item.material] || 0) + 1;
      }
    });
    
    setMaterialData(materials);
  };

  const handleVoiceCommand = (command, data) => {
    switch (command) {
      case 'analyze':
        handleAnalyze();
        break;
      case 'upload':
        if (fileInputRef.current) {
          fileInputRef.current.click();
        }
        break;
      case 'addItem':
        if (data) {
          const newItem = {
            id: Date.now(),
            name: data.name,
            category: data.category,
            material: data.material
          };
          setManualItems(prev => [...prev, newItem]);
        }
        break;
      case 'switchLanguage':
        setLanguage(prev => prev === 'en' ? 'ta' : 'en');
        break;
      default:
        console.log('Unknown voice command:', command);
    }
  };

  const getMissingItems = () => {
    // Mock logic for missing items based on event type
    const requiredItems = {
      wedding: ['Flowers', 'Chairs', 'Lights', 'Fabric', 'Tables'],
      birthday: ['Balloons', 'Chairs', 'Lights', 'Decorations'],
      corporate: ['Chairs', 'Tables', 'Lights', 'Banners']
    };

    const currentItems = [...detectedItems, ...manualItems].map(item => item.name);
    const required = requiredItems[selectedEvent] || [];
    return required.filter(item => !currentItems.some(current => 
      current.toLowerCase().includes(item.toLowerCase())
    ));
  };

  const t = translations[language];
  const missingItems = getMissingItems();
  const allMaterialsPresent = missingItems.length === 0 && (detectedItems.length > 0 || manualItems.length > 0);

  return (
    <div className="App">
      <header className="app-header">
        <h1>{t.title}</h1>
        <div className="header-controls">
          <LanguageToggle language={language} setLanguage={setLanguage} />
          <VoiceOutput 
            materialData={materialData}
            language={language}
            translations={translations}
            allMaterialsPresent={allMaterialsPresent}
            missingItems={missingItems}
          />
        </div>
      </header>

      <main className="app-main">
        {loading && <PandaLoader message={t.analyzing} />}
        
        {error && (
          <div className="app-card" style={{ background: 'rgba(244, 67, 54, 0.1)', borderColor: 'rgba(244, 67, 54, 0.3)' }}>
            <p style={{ color: '#D32F2F', textAlign: 'center', margin: 0 }}>{error}</p>
          </div>
        )}

        <div className="app-flow">
          {/* Voice Commands */}
          <VoiceCommands 
            language={language}
            onVoiceCommand={handleVoiceCommand}
          />

          {/* Upload Section */}
          <div className="app-card">
            <FileUpload 
              onFileUpload={setUploadedFile}
              uploadedFile={uploadedFile}
              language={language}
              ref={fileInputRef}
            />
          </div>

          {/* Event Selection */}
          <div className="app-card">
            <EventSelection 
              selectedEvent={selectedEvent}
              setSelectedEvent={setSelectedEvent}
              language={language}
            />
          </div>

          {/* Manual Input */}
          <div className="app-card">
            <ManualInput 
              items={manualItems}
              setItems={setManualItems}
              language={language}
            />
          </div>

          {/* Analyze Button */}
          <div className="analyze-section">
            <button 
              className="analyze-btn"
              onClick={handleAnalyze}
              disabled={loading}
            >
              {t.analyze}
            </button>
          </div>

          {/* Results Section */}
          {showResults && (
            <div className="results-section">
              {/* Status Message */}
              <div className={`status-message ${allMaterialsPresent ? 'status-success' : 'status-warning'}`}>
                {allMaterialsPresent ? t.allMaterialsPresent : t.someMaterialsMissing}
                {missingItems.length > 0 && (
                  <div style={{ marginTop: '1rem' }}>
                    <strong>{t.missingItems}</strong>
                    <div className="missing-items">
                      {missingItems.join(', ')}
                    </div>
                  </div>
                )}
              </div>

              {/* Chart Visualization */}
              <div className="app-card">
                <MaterialChart 
                  data={materialData}
                  language={language}
                />
              </div>

              {/* Detected Items */}
              <div className="app-card">
                <DetectedItems 
                  items={detectedItems}
                  language={language}
                />
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
